async (params, browser) => {
  // Open stream page
  await browser.open(`https://www.twitch.tv/${params.channel_name}`)

  // Wait for chat to load
  await browser.waitForSelector('[class*=\'chat-line\'], [data-a-target=\'chat-line-message\'], [class*=\'chat-scrollable\']', 15000)

  // Wait for chat messages to accumulate
  await browser.wait(5000)

  // Extract chat messages
  const chat_data = await browser.evaluate(`const messages = []; const chatLines = document.querySelectorAll('[data-a-target="chat-line-message"], [class*="chat-line__message"], [class*="chat-line"]'); for (let i = Math.max(0, chatLines.length - 50); i < chatLines.length; i++) { const el = chatLines[i]; const usernameEl = el.querySelector('[data-a-target="chat-message-username"], [class*="chat-author"], button[data-a-user]'); const messageEl = el.querySelector('[data-a-target="chat-message-text"], [class*="text-fragment"], span[class*="message"]'); const badges = []; el.querySelectorAll('[class*="badge"] img, [data-a-target="chat-badge"]').forEach(function(badge) { const alt = badge.getAttribute('alt') || badge.getAttribute('aria-label') || ''; if (alt) badges.push(alt); }); if (usernameEl || messageEl) { messages.push({ username: usernameEl ? usernameEl.textContent.trim() : '', message: messageEl ? messageEl.textContent.trim() : el.textContent.trim().substring(0, 500), badges: badges }); } } const isLive = !!document.querySelector('[class*="live-indicator"]'); const viewersEl = document.querySelector('[data-a-target="animated-channel-viewers-count"]'); return { channel_name: '' + params.channel_name + '', is_live: isLive, viewer_count: viewersEl ? viewersEl.textContent.trim() : '', message_count: messages.length, messages: messages, url: window.location.href }`)

  return chat_data
}
